const body = $input.first().json.body;

const errors = [];

if (!body.transcript_text || body.transcript_text.trim().length < 100) {
  errors.push('transcript_text is required and must be at least 100 characters');
}
if (!body.company_name) {
  errors.push('company_name is required');
}
if (!body.call_date) {
  errors.push('call_date is required (YYYY-MM-DD)');
}

if (errors.length > 0) {
  return [{ json: { valid: false, errors, status: 400 } }];
}

// Build slugs
const ticker = (body.ticker || body.company_name.replace(/\s+/g,'').substring(0,6)).toUpperCase();
const fiscal_quarter = body.fiscal_quarter || 'UNKNOWN';
const quarter_slug = fiscal_quarter.replace(/\s+/g,'-').toUpperCase();

return [{
  json: {
    valid: true,
    company_name: body.company_name,
    ticker,
    call_date: body.call_date,
    fiscal_quarter,
    fiscal_year: body.fiscal_year || null,
    call_type: body.call_type || 'quarterly',
    transcript_source: body.transcript_source || 'manual',
    transcript_text: body.transcript_text,
    word_count: body.transcript_text.trim().split(/\s+/).length,
    quarter_slug
  }
}];

const response = $input.first().json;
const callContext = $('Set Call Context').first().json;

// Groq format
const rawText = response.choices?.[0]?.message?.content || '{}';
let parsed;
try {
  const clean = rawText.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  return [{ json: { error: 'Section parse failed: ' + e.message, raw: rawText, earnings_call_id: callContext.earnings_call_id } }];
}

// Enrich each section with call context
const sections = (parsed.sections || []).map((s, idx) => ({
  ...s,
  earnings_call_id: callContext.earnings_call_id,
  company_name: callContext.company_name,
  ticker: callContext.ticker,
  fiscal_quarter: callContext.fiscal_quarter,
  quarter_slug: callContext.quarter_slug,
  transcript_text: callContext.transcript_text,
  section_order: s.section_order || idx + 1
}));

return sections.map(s => ({ json: s }));

const response = $input.first().json;
const sectionCtx = $('Process Section Response').item.json;
const rawText = response.choices?.[0]?.message?.content || '{}';
let parsed;
try {
  const clean = rawText.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  return [{ json: { guidance_signals: [], parse_error: e.message } }];
}
const runLog = {
  earnings_call_id: sectionCtx.earnings_call_id,
  run_type: 'guidance_extract',
  model_used: 'llama-3.3-70b-versatile',
  prompt_tokens: response.usage?.prompt_tokens || 0,
  completion_tokens: response.usage?.completion_tokens || 0,
  success: true,
  raw_llm_response: rawText
};
const signals = (parsed.guidance_signals || []).map((g, idx) => ({
  ...g,
  earnings_call_id: sectionCtx.earnings_call_id,
  claim_id: g.claim_id || `${sectionCtx.ticker}-${sectionCtx.quarter_slug}-G${String(idx+1).padStart(3,'0')}`,
  schema_valid: !!g.direction && !!g.transcript_citation && !!g.claim_text,
  validation_errors: [
    !g.direction && 'direction is required',
    !g.transcript_citation && 'transcript_citation is required',
    !g.claim_text && 'claim_text is required'
  ].filter(Boolean),
  falsification_flag: g.falsification_flag || !g.direction || !g.transcript_citation || (g.direction_confidence || 0) < 0.5,
  run_log: runLog
}));
return signals.length > 0 
  ? signals.map(s => ({ json: s }))
  : [{ json: { guidance_signals_empty: true, earnings_call_id: sectionCtx.earnings_call_id } }];

const response = $input.first().json;
const sectionCtx = $('Process Section Response').item.json;

const rawText = response.choices?.[0]?.message?.content || '{}';
let parsed;
try {
  const clean = rawText.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  return [{ json: { risk_admissions: [], parse_error: e.message } }];
}

const runLog = {
  earnings_call_id: sectionCtx.earnings_call_id,
  run_type: 'risk_extract',
  model_used: 'claude-opus-4-6',
  prompt_tokens: response.usage?.input_tokens || 0,
  completion_tokens: response.usage?.output_tokens || 0,
  success: true
};

const risks = (parsed.risk_admissions || []).map((r, idx) => ({
  ...r,
  earnings_call_id: sectionCtx.earnings_call_id,
  claim_id: r.claim_id || `${sectionCtx.ticker}-${sectionCtx.quarter_slug}-R${String(idx+1).padStart(3,'0')}`,
  schema_valid: !!r.risk_category && !!r.transcript_citation && !!r.severity,
  run_log: runLog
}));

return risks.length > 0
  ? risks.map(r => ({ json: r }))
  : [{ json: { risk_admissions_empty: true, earnings_call_id: sectionCtx.earnings_call_id } }];

const response = $input.first().json;
const sectionCtx = $('Process Section Response').item.json;

const rawText = response.content?.[0]?.text || '{}';
let parsed;
try {
  const clean = rawText.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  return [{ json: { qa_pressure_map: [], parse_error: e.message } }];
}

const runLog = {
  earnings_call_id: sectionCtx.earnings_call_id,
  run_type: 'qa_map',
  model_used: 'claude-opus-4-6',
  prompt_tokens: response.usage?.input_tokens || 0,
  completion_tokens: response.usage?.output_tokens || 0,
  success: true
};

const qaItems = (parsed.qa_pressure_map || []).map(q => ({
  ...q,
  earnings_call_id: sectionCtx.earnings_call_id,
  schema_valid: !!q.question_topic && !!q.response_type,
  // Clamp pressure score
  pressure_score: Math.min(10, Math.max(1, q.pressure_score || 5)),
  run_log: runLog
}));

return qaItems.length > 0
  ? qaItems.map(q => ({ json: q }))
  : [{ json: { qa_empty: true, earnings_call_id: sectionCtx.earnings_call_id } }];

const response = $input.first().json;
const callCtx = $('Set Call Context').first().json;
const aggData = $('Fetch All Signals for Summary').first().json;
const rawText = response.choices?.[0]?.message?.content || '{}';
let parsed;
try {
  const clean = rawText.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = {
    overall_tone: 'neutral',
    tone_confidence: 0,
    what_changed: 'Summary generation failed',
    what_didnt_change: '',
    narrative_summary: 'Summary generation failed: ' + e.message
  };
}

// Group guidance by direction
const guidance = aggData.guidance_signals || [];
const groupByDir = (dir) => guidance.filter(g => g.direction === dir).map(g => g.claim_id);

return [{
  json: {
    earnings_call_id: callCtx.earnings_call_id,
    guidance_strengthened: JSON.stringify(groupByDir('strengthened')),
    guidance_weakened:     JSON.stringify(groupByDir('weakened')),
    guidance_unchanged:    JSON.stringify(groupByDir('unchanged')),
    new_signals:           JSON.stringify(groupByDir('new')),
    retracted_signals:     JSON.stringify(groupByDir('retracted')),
    top_pressure_topics:   JSON.stringify(parsed.top_pressure_topics || []),
    new_risks:             JSON.stringify((aggData.risk_admissions || []).filter(r => r.is_new_risk).map(r => r.claim_id)),
    overall_tone:          parsed.overall_tone || 'neutral',
    tone_confidence:       parsed.tone_confidence || 0,
    narrative_summary:     parsed.narrative_summary || '',
    what_changed:          parsed.what_changed || '',
    what_didnt_change:     parsed.what_didnt_change || '',
    contradiction_flags:   JSON.stringify(parsed.contradiction_flags || []),
    schema_valid:          !!parsed.narrative_summary && !!parsed.overall_tone,
    decision_grade_signals: parsed.decision_grade_signals || []
  }
}];

const callResult = $input.first().json;
const summaryData = $('Process Summary Response').first().json;

// Falsification check
const falsificationFailed = summaryData.guidance_strengthened === '[]' &&
  summaryData.guidance_weakened === '[]' &&
  summaryData.guidance_unchanged === '[]' &&
  summaryData.new_signals === '[]';

return [{
  json: {
    success: true,
    earnings_call_id: callResult.id,
    company: callResult.company_name,
    ticker: callResult.ticker,
    quarter: callResult.fiscal_quarter,
    status: callResult.processing_status,
    overall_tone: summaryData.overall_tone,
    narrative_summary: summaryData.narrative_summary,
    what_changed: summaryData.what_changed,
    decision_grade_signals: summaryData.decision_grade_signals,
    falsification_warning: falsificationFailed ? 'WARNING: No guidance signals extracted — schema may need redesign' : null,
    schema_valid: summaryData.schema_valid
  }
}];

